using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow (compile-time data)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero price yields zero total")]
    [DataRow(99.99, 0, 0.20, 0.00,   DisplayName = "Zero quantity yields zero total")]
    public void CalculateTotal_WithDataRow_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – DynamicData (runtime data)
    //  Allows decimal precision without double casts.
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> CalculateTotalCases
    {
        get
        {
            yield return [10.00m, 1,  0.0m,  10.00m];   // no tax
            yield return [10.00m, 1,  0.10m, 11.00m];   // 10% tax
            yield return [25.50m, 4,  0.08m, 110.16m];  // 8% tax
            yield return [0.01m,  1,  0.0m,  0.01m];    // penny item
            yield return [100.0m, 10, 0.25m, 1250.0m];  // bulk with 25% tax
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – invalid inputs
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.0, 1,  0.10, DisplayName = "Negative unit price")]
    [DataRow(10.0, -1, 0.10, DisplayName = "Negative quantity")]
    [DataRow(10.0, 1,  -0.1, DisplayName = "Negative tax rate")]
    [DataRow(10.0, 1,  1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidInput_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.0, 0.0,   100.0,  DisplayName = "0% discount — full price")]
    [DataRow(100.0, 50.0,  50.0,   DisplayName = "50% discount — half price")]
    [DataRow(100.0, 100.0, 0.0,    DisplayName = "100% discount — free")]
    [DataRow(200.0, 25.0,  150.0,  DisplayName = "25% off $200")]
    [DataRow(0.0,   10.0,  0.0,    DisplayName = "Zero price stays zero")]
    public void ApplyDiscount_WithDataRow_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (method source)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> GetDiscountEdgeCases()
    {
        yield return [59.99m, 15.0m,  50.9915m];  // fractional result
        yield return [1000m,  0.01m,  999.90m];    // tiny discount
        yield return [0.01m,  99.99m, 0.000001m];  // near-total discount on a penny
    }

    [TestMethod]
    [DynamicData(nameof(GetDiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_EdgeCases_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – invalid inputs
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.0, -1.0,  DisplayName = "Negative discount")]
    [DataRow(100.0, 100.1, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(
        double price, double discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }

    // ───────────────────────────────────────────────
    //  FormatPrice – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(9.9,    "$",  "$9.90",    DisplayName = "Default dollar symbol")]
    [DataRow(1234.5, "€",  "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.0,    "£",  "£0.00",    DisplayName = "Zero with pound")]
    public void FormatPrice_WithSymbol_ReturnsFormatted(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

